## Min Stack: O(1) Minimum Retrieval

Design a stack that supports push, pop, peek, and retrieving the minimum element — all in O(1) time.

**Key insight:** Alongside the main stack, maintain an auxiliary 'min stack'. Each slot in the min stack records the current minimum at that depth. When you push, push `min(val, current_min)` onto the min stack. When you pop, pop from both stacks simultaneously.

```python
class MinStack:
    def __init__(self):
        self._stack = []      # stores actual values
        self._min_stack = []  # stores current min at each level

    def push(self, val: int) -> None:
        self._stack.append(val)
        current_min = val if not self._min_stack else min(val, self._min_stack[-1])
        self._min_stack.append(current_min)

    def pop(self) -> None:
        if not self._stack:
            raise IndexError("pop from empty stack")
        self._stack.pop()
        self._min_stack.pop()

    def top(self) -> int:
        return self._stack[-1]

    def get_min(self) -> int:
        return self._min_stack[-1]


# Space-optimised variant: store only when min changes
class MinStackOptimised:
    def __init__(self):
        self._stack = []
        self._min_stack = []  # (min_value, count)

    def push(self, val: int) -> None:
        self._stack.append(val)
        if not self._min_stack or val < self._min_stack[-1][0]:
            self._min_stack.append([val, 1])
        elif val == self._min_stack[-1][0]:
            self._min_stack[-1][1] += 1

    def pop(self) -> None:
        val = self._stack.pop()
        if val == self._min_stack[-1][0]:
            self._min_stack[-1][1] -= 1
            if self._min_stack[-1][1] == 0:
                self._min_stack.pop()

    def top(self) -> int:
        return self._stack[-1]

    def get_min(self) -> int:
        return self._min_stack[-1][0]
```

```java
import java.util.Deque;
import java.util.ArrayDeque;

public class MinStack {
    private final Deque<Integer> stack = new ArrayDeque<>();
    private final Deque<Integer> minStack = new ArrayDeque<>();

    public void push(int val) {
        stack.push(val);
        int currentMin = minStack.isEmpty() ? val : Math.min(val, minStack.peek());
        minStack.push(currentMin);
    }

    public void pop() {
        stack.pop();
        minStack.pop();
    }

    public int top()    { return stack.peek(); }
    public int getMin() { return minStack.peek(); }
}
```

**Complexity**
- All operations: O(1) time
- Space: O(n) for both implementations

**Interview Tip:** Interviewers sometimes follow up with 'can you do this with O(1) extra space?' The trick is to store the difference between the value and the current min: push `val - current_min` and encode the new min inline. This gets tricky with negative numbers — walk through the math carefully on a whiteboard.

