## Circular Queue Implementation

A circular queue (ring buffer) uses a fixed-size array with head and tail pointers that wrap around, avoiding the wasted space of a naive dequeue-from-front approach.

**Design:** Track `head` (next dequeue position) and `tail` (next enqueue position) with a `size` counter. Wrap indices using modulo arithmetic.

```python
class CircularQueue:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.data = [None] * capacity
        self.head = 0
        self.tail = 0
        self.size = 0

    def enqueue(self, val) -> bool:
        if self.is_full():
            return False
        self.data[self.tail] = val
        self.tail = (self.tail + 1) % self.capacity
        self.size += 1
        return True

    def dequeue(self):
        if self.is_empty():
            return None
        val = self.data[self.head]
        self.data[self.head] = None  # help GC
        self.head = (self.head + 1) % self.capacity
        self.size -= 1
        return val

    def front(self):
        if self.is_empty():
            return None
        return self.data[self.head]

    def rear(self):
        if self.is_empty():
            return None
        return self.data[(self.tail - 1) % self.capacity]

    def is_empty(self) -> bool:
        return self.size == 0

    def is_full(self) -> bool:
        return self.size == self.capacity


# Demo
cq = CircularQueue(3)
cq.enqueue(1)
cq.enqueue(2)
cq.enqueue(3)
print(cq.is_full())   # True
cq.dequeue()
cq.enqueue(4)         # wraps around
print(cq.rear())      # 4
```

```java
public class CircularQueue {
    private final int[] data;
    private int head, tail, size;

    public CircularQueue(int capacity) {
        data = new int[capacity];
        head = tail = size = 0;
    }

    public boolean enqueue(int val) {
        if (isFull()) return false;
        data[tail] = val;
        tail = (tail + 1) % data.length;
        size++;
        return true;
    }

    public int dequeue() {
        if (isEmpty()) throw new RuntimeException("Queue is empty");
        int val = data[head];
        head = (head + 1) % data.length;
        size--;
        return val;
    }

    public int front()  { return isEmpty() ? -1 : data[head]; }
    public int rear()   { return isEmpty() ? -1 : data[(tail - 1 + data.length) % data.length]; }
    public boolean isEmpty() { return size == 0; }
    public boolean isFull()  { return size == data.length; }
}
```

**Complexity**
- All operations: O(1) time
- Space: O(capacity)

**Interview Tip:** This is the foundation of many systems — OS scheduler ready queues, producer-consumer buffers, BFS level-order traversal. Interviewers may ask you to handle thread safety; mention `synchronized` blocks in Java or `threading.Lock` in Python, and explain why you need to check the condition inside the lock.

